I18N.register("fr", {
  tips: {
    "Look at Rows and Columns Separately": ["Examinez lignes et colonnes séparément", "Dans une grille de nombres, étudiez d’abord chaque ligne, puis chaque colonne. Souvent, une seule direction suffit pour deviner la règle (progressions du type +2, +3, ×2, etc.)."],
    "Find the Rule Between Numbers": ["Trouvez la règle entre les nombres", "Demandez-vous : faut-il ajouter, soustraire, multiplier ou diviser pour passer d’un terme au suivant ? Testez chaque opération jusqu’à ce que la même règle marche partout."],
    "Watch for Repeating Groups": ["Repérez les groupes répétitifs", "Un groupe de formes ou de symboles peut se répéter en boucle : comptez combien d’éléments il contient, puis repérez où vous en êtes dans le cycle."],
    "Use Elimination": ["Procédez par élimination", "En cas de doute, essayez chaque réponse : insérez-la dans le motif et vérifiez si la règle reste valable. Écartez tout choix qui casse la régularité."],
    "Find the Difference": ["Cherchez la différence", "Soustrayez chaque nombre du précédent. Si l’écart est toujours le même, la suite est probablement arithmétique (même ajout ou même retrait à chaque fois)."],
    "Try Multiplying or Dividing": ["Essayez multiplier ou diviser", "Divisez chaque terme par le précédent. Si le quotient est constant, la suite est géométrique (même facteur à chaque étape)."],
    "Check for Two-Step Rules": ["Repérez les règles à deux temps", "La règle peut combiner deux opérations (par exemple +2 puis ×2). Notez les étapes sur le brouillon et appliquez-les dans le bon ordre."],
    "Write It Down": ["Notez sur le papier", "Inscrivez les nombres et, sous eux, les différences ou les rapports : le motif apparaît souvent plus clairement qu’en restant dans la tête."],
    "Read Every Word Carefully": ["Relisez chaque mot", "En logique, des termes comme « tous », « certains », « aucun », « exactement » changent le sens. Lisez l’énoncé deux fois avant de répondre."],
    "Draw a Picture or List": ["Dessinez ou listez", "Notez les personnes, les moments ou les relations : une liste ou un schéma simple clarifie souvent qui est le plus grand, qui arrive en premier, etc."],
    "Watch Out for Traps": ["Méfiez-vous des pièges", "De « tous les chiens sont des animaux », on ne peut pas conclure que « tous les animaux sont des chiens ». Ne renversez pas la règle par inadvertance."],
    "Use 'If... Then...' Thinking": ["Raisonnez en « si… alors… »", "Reformulez : « si A est vrai, alors B ». Enchaînez les implications : si A, qu’est-ce qui doit suivre ?"],
    "Picture It in Your Mind": ["Visualisez dans votre tête", "Pour cubes et solides, imaginez la rotation ou le dépliage : un petit croquis sur le brouillon suffit souvent."],
    "Know the Basics of Common Shapes": ["Retenez les solides usuels", "Exemples utiles : le cube a 6 faces, 12 arêtes et 8 sommets ; le prisme à base triangulaire a 5 faces. Mémorisez ces repères pour aller plus vite."],
    "Count What You Cannot See": ["Comptez aussi l’invisible", "Lorsque des cubes sont collés, les faces en contact ne sont pas visibles : retranchez-les du total de faces libres."],
    "Use Nets to Understand Folding": ["Utilisez le patron (développement)", "Le patron d’un solide montre quelles faces sont voisines : suivez une face sur le patron pour voir à quelle autre elle se joint après pliage."],
    "Read the Problem Twice": ["Relisez l’énoncé", "Beaucoup d’erreurs viennent de la précipitation. La deuxième lecture fait souvent apparaître des expressions comme « tout sauf », « il reste » ou « en tout »."],
    "Look for Trick Words": ["Repérez les mots pièges", "Formules du type « tout sauf », « il reste », « au total », « chacun » modifient le calcul : soulignez-les."],
    "Break It Into Steps": ["Découpez le travail", "Commencez par ce que vous savez avec certitude, puis ajoutez ou retranchez selon l’énoncé. Évitez de tout traiter d’un seul bloc."],
    "Check Your Answer": ["Contrôlez votre réponse", "Après le calcul, demandez-vous si le résultat est plausible dans le contexte. En cas de doute, refaites l’opération."],
  },
  q: {
    "TPR811_1_01": ["Quelle est la prochaine étape ? 2, 4, 6, 8, __", "Comptez de 2 à 2.", ["9", "10", "12", "11"], "La chaîne augmente de 2 à chaque pas : 2, 4, 6, 8, 10."],
    "TPR811_1_02": ["Quelle est la prochaine étape ? 5, 10, 15, 20, __", "Les nombres sont des multiples du même nombre de base.", ["22", "30", "25", "24"], "La chaîne augmente de 5 à chaque pas : 5, 10, 15, 20, 25."],
    "TPR811_1_03": ["Quelle est la prochaine étape ? 3, 6, 9, 12, __", "Pensez à multiplier par 3 (le tableau 3).", ["14", "15", "16", "13"], "La chaîne augmente de 3 à chaque pas : 3, 6, 9, 12, 15."],
    "TPR811_1_04": ["Quelle est la prochaine étape ? 10, 20, 30, 40, __", "Comptez de 10 à 10.", ["45", "55", "50", "60"], "La chaîne augmente de 10 à chaque pas : 10, 20, 30, 40, 50."],
    "TPR811_1_05": ["Quelle est la prochaine étape ? 4, 8, 12, 16, __", "Ce sont des multiples de 4.", ["18", "22", "24", "20"], "La chaîne augmente de 4 à chaque pas : 4, 8, 12, 16, 20."],
    "TPR811_1_06": ["Quel est le numéro manquant ? 1, 3, 5, __, 9", "Ce sont des nombres impairs.", ["6", "8", "7", "4"], "Ce sont des nombres impairs qui augmentent de 2 : 1, 3, 5, 7, 9."],
    "TPR811_1_07": ["Quelle est la prochaine étape ? 2, 5, 8, 11, __", "Combien cela représente-t-il à chaque fois ?", ["12", "13", "15", "14"], "Chaque nombre est 3 de plus que le précédent : 2, 5, 8, 11, 14."],
    "TPR811_1_08": ["Quel est le numéro manquant ? 6, 12, __, 24, 30", "Comptez de 6 à 6.", ["15", "18", "20", "16"], "La chaîne augmente de 6 : 6, 12, 18, 24, 30."],
    "TPR811_1_09": ["Quelle est la prochaine étape ? ○, □, ○, □, ○, __", "Les formes alternent.", ["○", "△", "□", "◇"], "Cercle et carré alternés. Après le cercle vient le carré : ○, □, ○, □, ○, □."],
    "TPR811_1_10": ["Quelle est la prochaine étape ? 7, 14, 21, 28, __", "Pensez à multiplier par 7 (le tableau 7).", ["30", "32", "36", "35"], "La chaîne augmente de 7 à chaque pas : 7, 14, 21, 28, 35."],
    "TPR811_1_11": ["Quel est le numéro manquant ? 10, __, 30, 40, 50", "Comptez de 10 à 10.", ["15", "25", "20", "12"], "La chaîne augmente de 10 : 10, 20, 30, 40, 50."],
    "TPR811_1_12": ["Quelle est la prochaine étape ? 1, 4, 7, 10, __", "Combien cela représente-t-il à chaque fois ?", ["12", "14", "11", "13"], "Chaque nombre est 3 de plus que le précédent : 1, 4, 7, 10, 13."],
    "TPR811_1_13": ["Quelle est la prochaine étape ? A, B, A, B, A, __", "Les lettres alternent.", ["A", "C", "B", "D"], "Alternate A and B: A, B, A, B, A, B."],
    "TPR811_1_14": ["Quelle est la prochaine étape ? 8, 16, 24, 32, __", "Ce sont des multiples de 8.", ["36", "38", "40", "42"], "La chaîne augmente de 8 : 8, 16, 24, 32, 40."],
    "TPR811_1_15": ["Quel est le numéro manquant ? 5, 10, __, 20, 25", "Comptez de 5 à 5.", ["12", "14", "16", "15"], "La chaîne augmente de 5 : 5, 10, 15, 20, 25."],
    "TPR811_1_16": ["Quelle est la prochaine étape ? 9, 18, 27, 36, __", "Ce sont des multiples de 9.", ["45", "40", "42", "44"], "La chaîne augmente de 9 : 9, 18, 27, 36, 45."],
    "TPR811_1_17": ["Quelle est la prochaine étape ? ★, ♥, ★, ♥, ★, __", "Deux symboles alternent.", ["★", "♥", "♦", "○"], "Étoile et cœur alternés : ★, ♥, ★, ♥, ★, ♥."],
    "TPR811_1_18": ["Quel est le numéro manquant ? 2, 4, __, 8, 10", "Comptez de 2 à 2.", ["5", "7", "6", "3"], "La chaîne augmente de 2 : 2, 4, 6, 8, 10."],
    "TPR811_1_19": ["Quelle est la prochaine étape ? 11, 22, 33, 44, __", "Ce sont des multiples de 11.", ["50", "55", "54", "56"], "La chaîne augmente de 11 : 11, 22, 33, 44, 55."],
    "TPR811_1_20": ["Quelle est la prochaine étape ? 1, 2, 1, 2, 1, __", "Les chiffres répètent toujours la même chose.", ["1", "3", "2", "0"], "Les nombres 1 et 2 alternent : 1, 2, 1, 2, 1, 2."],
    "TPR811_2_01": ["Dans une grille, la ligne 1 est : 2, 4, 6, 8. la ligne 2 est : 3, 6, 9, 12. la ligne 3 est : 4, 8, __, 16. Quel est le nombre manquant ?", "Chaque ligne contient des multiples du premier nombre de cette ligne.", ["10", "11", "12", "14"], "La rangée 3 contient des multiples de 4 : 4, 8, 12, 16."],
    "TPR811_2_02": ["Quelle est la prochaine étape ? 1, 2, 4, 8, __", "Chaque numéro est doublé.", ["10", "12", "14", "16"], "Chaque nombre est multiplié par 2 : 1, 2, 4, 8, 16."],
    "TPR811_2_03": ["Quelle est la prochaine étape ? 3, 9, 27, __", "Chaque nombre est multiplié par le même facteur.", ["36", "54", "81", "30"], "Chaque nombre est multiplié par 3 : 3, 9, 27, 81."],
    "TPR811_2_04": ["Quelle est la prochaine étape dans la chaîne ? △, △, □, △, △, □, △, △, __", "Recherche le groupe de symboles répétitifs.", ["△", "□", "○", "★"], "Le motif répète △, △, □ toujours de la même manière. La position 9 est □."],
    "TPR811_2_05": ["Grille : la ligne 1 est 1, 2, 3. La ligne 2 est 2, 4, 6. La ligne 3 est 3, 6, __. Quel est le numéro manquant ?", "Chaque ligne multiplie la première ligne par le numéro de ligne.", ["7", "8", "9", "10"], "Rangée 3 = rangée du haut × 3. Donc 3 × 3 = 9."],
    "TPR811_2_06": ["Quelle est la prochaine étape ? 2, 6, 18, 54, __", "Multipliez par le même nombre à chaque fois.", ["108", "162", "72", "60"], "Chaque nombre est multiplié par 3 : 2, 6, 18, 54, 162."],
    "TPR811_2_07": ["Quelle est la prochaine étape ? 64, 32, 16, __", "Chaque numéro est divisé par deux.", ["12", "10", "4", "8"], "Chaque nombre est divisible par 2 : 64, 32, 16, 8."],
    "TPR811_2_08": ["Grille : La rangée 1 est 1, 3, 5, 7. La rangée 2 est 2, 6, 10, 14. La rangée 3 est 3, 9, __, 21. Quel est le nombre manquant ?", "Rangée 2 = Rangée 1 × 2. Combien coûte la rangée 3 ?", ["12", "15", "13", "17"], "Rangée 3 = Rangée 1 × 3. Donc 5 × 3 = 15."],
    "TPR811_2_09": ["Quelle est la prochaine étape ? 4, 8, 16, 32, __", "Chaque numéro est doublé.", ["48", "40", "64", "36"], "Chaque nombre est multiplié par 2 : 4, 8, 16, 32, 64."],
    "TPR811_2_10": ["Quelle est la prochaine étape ? ★, ♦, ♦, ★, ♦, ♦, ★, ♦, ♦, ★, __", "Trouvez le groupe répétitif.", ["★", "♦", "○", "□"], "Le motif se répète ★, ♦, ♦. La position 11 est ♦."],
    "TPR811_2_11": ["Quelle est la prochaine étape ? 5, 25, 125, __", "Multipliez par le même nombre à chaque fois.", ["150", "500", "250", "625"], "Chaque nombre est multiplié par 5 : 5, 25, 125, 625."],
    "TPR811_2_12": ["Grille : la rangée 1 correspond à 2, 4, 6. La rangée 2 correspond à 3, 6, 9. La rangée 3 correspond à 5, 10, __. Quel est le numéro manquant ?", "Chaque ligne contient des multiples du premier nombre de cette ligne.", ["12", "14", "15", "20"], "La rangée 3 contient des multiples de 5 : 5, 10, 15."],
    "TPR811_2_13": ["Quelle est la prochaine étape ? 1, 4, 9, 16, __", "Ce sont des carrés parfaits : 1², 2², 3², 4²...", ["20", "25", "24", "36"], "Ce sont des nombres carrés : 1, 4, 9, 16, 25 (qui a 1², 2², 3², 4², 5²)."],
    "TPR811_2_14": ["Quelle est la prochaine étape ? A, A, B, A, A, B, A, A, B, __", "Trouvez le groupe répétitif de 3.", ["A", "B", "C", "D"], "Le motif répète A, A, B. La position 10 démarre un nouveau groupe commençant par A."],
    "TPR811_2_15": ["Quelle est la prochaine étape ? 1, 1, 2, 3, 5, 8, __", "Additionnez les deux nombres précédents.", ["10", "11", "12", "13"], "Chaque nombre est la somme des deux qui le précèdent : 5 + 8 = 13. C'est la suite de Fibonacci."],
    "TPR811_2_16": ["Grille : La rangée 1 est 1, 2, 3, 4. La rangée 2 est 2, 4, 6, 8. La rangée 3 est 4, 8, __, 16. Quel est le nombre manquant ?", "Rangée 3 = Rangée 1 × 4.", ["10", "12", "14", "9"], "Rangée 3 = Rangée 1 × 4. Donc 3 × 4 = 12."],
    "TPR811_2_17": ["Quelle est la prochaine étape ? 10, 100, 1000, __", "Multipliez par 10 à chaque étape.", ["1100", "2000", "10000", "5000"], "Chaque nombre est multiplié par 10 : 10, 100, 1000, 10000."],
    "TPR811_2_18": ["Quelle est la prochaine étape ? 1, 3, 6, 10, __", "Regardez les différences : +2, +3, +4…", ["13", "14", "15", "12"], "La différence augmente de 1 à chaque pas : +2, +3, +4, +5. Donc 10 + 5 = 15. Ce sont des nombres triangulaires."],
    "TPR811_2_19": ["Quelle est la prochaine étape ? 1000, 500, 250, 125, __", "Chaque numéro est divisé par deux.", ["62,5", "100", "75", "60"], "Chaque nombre est divisible par 2 : 1000, 500, 250, 125, 62,5."],
    "TPR811_2_20": ["Quelle est la prochaine étape ? 1, 8, 27, 64, __", "Ce sont des nombres cubes : 1³, 2³, 3³, 4³...", ["100", "81", "125", "216"], "Ce sont des nombres cubes : 1³=1, 2³=8, 3³=27, 4³=64, 5³=125."],
    "TPR811_3_01": ["Quelle est la prochaine étape ? 1, 3, 7, 15, __", "Essayez de multiplier par 2 puis d'ajouter 1.", ["29", "30", "31", "23"], "Règle : ×2 puis +1. 1 → 3, 3 → 7, 7 → 15, 15 → 31."],
    "TPR811_3_02": ["Quelle est la prochaine étape ? 2, 5, 11, 23, __", "Essayez ×2 puis +1.", ["35", "46", "47", "45"], "Règle : ×2 puis +1. 2 → 5, 5 → 11, 11 → 23, 23 → 47."],
    "TPR811_3_03": ["Quelle est la prochaine étape ? ○, ○, □, △, ○, ○, □, △, ○, ○, __", "Trouvez le groupe de 4 symboles répétitifs.", ["○", "△", "□", "★"], "Le motif se répète : ○, ○, □, △. La position 11 est □."],
    "TPR811_3_04": ["Quelle est la prochaine étape ? 1, 4, 13, 40, __", "Essayez ×3 puis +1.", ["80", "121", "120", "81"], "Règle : ×3 puis +1. 1 → 4, 4 → 13, 13 → 40, 40 → 121."],
    "TPR811_3_05": ["Grille : la rangée 1 est 1, 4, 7. La rangée 2 est 3, 10, 17. La rangée 3 est 5, 16, __. Chaque ligne suit la même règle d'addition, et la colonne 1 a les valeurs 1, 3, 5. Quel est le nombre manquant ?", "Rang 1, rassemblez-en 3 à chaque étape. La rangée 2 en rassemble 7 à chaque étape. La ligne 3 ajoute... regardez les deux premiers nombres.", ["27", "25", "21", "23"], "Rangée 3 : 5, 16, 27. La différence est de 11 à chaque étape (5+11=16, 16+11=27)."],
    "TPR811_3_06": ["Quelle est la prochaine étape ? 2, 6, 14, 30, __", "Essayez ×2 puis +2.", ["58", "60", "62", "56"], "Règle : ×2 puis +2. 2 → 6, 6 → 14, 14 → 30, 30 → 62."],
    "TPR811_3_07": ["Quelle est la prochaine étape ? 3, 7, 15, 31, __", "Essayez ×2 puis +1.", ["47", "62", "63", "60"], "Règle : ×2 puis +1. 3 → 7, 7 → 15, 15 → 31, 31 → 63."],
    "TPR811_3_08": ["Quelle est la prochaine étape ? 1, 2, 5, 10, 17, __", "Regardez les différences entre les nombres : 1, 3, 5, 7...", ["24", "25", "26", "22"], "Les différences sont des nombres impairs : +1, +3, +5, +7, +9. Donc 17 + 9 = 26."],
    "TPR811_3_09": ["Grille : la rangée 1 est 1, 4, 7. La rangée 2 est 2, 8, 14. La rangée 3 est 3, 12, __. Quel est le numéro manquant ?", "Rangée 2 = Rangée 1 × 2. Rangée 3 = Rangée 1 × ?", ["18", "21", "15", "24"], "Rangée 3 = Rangée 1 × 3. Donc 7 × 3 = 21."],
    "TPR811_3_10": ["Quelle est la prochaine étape ? 0, 1, 3, 7, 15, __", "Essayez ×2 puis +1.", ["31", "30", "23", "29"], "Règle : ×2 puis +1. 0 → 1, 1 → 3, 3 → 7, 7 → 15, 15 → 31."],
    "TPR811_3_11": ["Quelle est la prochaine étape ? 2, 3, 5, 9, 17, __", "Regardez les différences : elles doublent à chaque étape.", ["25", "33", "31", "34"], "Les différences sont doublées : +1, +2, +4, +8, +16. Donc 17 + 16 = 33."],
    "TPR811_3_12": ["Quelle est la prochaine étape ? 1, 2, 6, 24, __", "1×2=2, 2×3=6, 6×4=24, 24× ?...", ["48", "120", "96", "30"], "Multipliez par des nombres croissants : ×2, ×3, ×4, ×5. Donc 24 × 5 = 120."],
    "TPR811_3_13": ["Grille : la rangée 1 est 2, 3, 4. La rangée 2 est 5, 7, 9. La rangée 3 est 11, 15, __. La règle entre les lignes est ×2 puis +1. Quel est le numéro manquant ?", "Appliquez la règle à chaque nombre de la ligne 2.", ["17", "18", "19", "21"], "9 × 2 + 1 = 19."],
    "TPR811_3_14": ["Quelle est la prochaine étape ? 100, 98, 94, 86, 70, __", "Regardez combien est soustrait : 2, 4, 8, 16...", ["54", "38", "50", "42"], "Les scadéions doublent : −2, −4, −8, −16, −32. Donc 70 − 32 = 38."],
    "TPR811_3_15": ["Quelle est la prochaine étape ? 1, 4, 10, 22, __", "Essayez ×2 puis +2.", ["44", "46", "34", "40"], "Règle : ×2 puis +2. 1 → 4, 4 → 10, 10 → 22, 22 → 46."],
    "TPR811_3_16": ["Quelle est la prochaine étape ? 5, 11, 23, 47, __", "Essayez ×2 puis +1.", ["94", "95", "93", "96"], "Règle : ×2 puis +1. 5 → 11, 11 → 23, 23 → 47, 47 → 95."],
    "TPR811_3_17": ["Quelle est la prochaine étape ? 1, 2, 4, 7, 11, 16, __", "L'écart augmente de 1 à chaque pas : +1, +2, +3, +4, +5...", ["21", "22", "20", "23"], "Différences : +1, +2, +3, +4, +5, +6. Donc 16 + 6 = 22."],
    "TPR811_3_18": ["Colonnes de la grille : la colonne 1 est 1, 2, 4. la colonne 2 est 1, 3, 9. la colonne 3 est 1, 4, __. Quel est le numéro manquant ?", "la colonne 1 correspond aux puissances de 2. la colonne 2 correspond aux puissances de 3. la colonne 3 correspond aux puissances de ?", ["8", "12", "16", "20"], "la colonne 3 est constituée de puissances de 4 : 4⁰=1, 4¹=4, 4²=16."],
    "TPR811_3_19": ["Quelle est la prochaine étape ? 2, 5, 14, 41, __", "Essayez ×3 puis −1.", ["82", "122", "123", "124"], "Règle : ×3 puis −1. 2 → 5, 5 → 14, 14 → 41, 41 → 122."],
    "TPR811_3_20": ["Quelle est la prochaine étape ? 1, 3, 9, 27, 81, __", "Chaque nombre est multiplié par 3.", ["162", "243", "108", "100"], "Chaque nombre est ×3 : 1, 3, 9, 27, 81, 243."],
    "TNR811_1_01": ["Combien font 3×4 ?", "Pensez à 3 groupes de 4.", ["7", "10", "12", "14"], "3 × 4 = 12."],
    "TNR811_1_02": ["Combien font 5 × 6 ?", "Pensez à 5 groupes de 6.", ["25", "30", "35", "36"], "5 × 6 = 30."],
    "TNR811_1_03": ["Quelle est la prochaine étape ? 5, 10, 15, 20, __", "Comptez de 5 à 5.", ["24", "25", "30", "22"], "Compter par 5 : 5, 10, 15, 20, 25."],
    "TNR811_1_04": ["Quel est le double de 8 ?", "Double signifie ×2.", ["14", "16", "18", "10"], "Double 8 = 8 × 2 = 16."],
    "TNR811_1_05": ["Combien font 4×7 ?", "Pensez à 4 groupes de 7.", ["24", "21", "28", "32"], "4 × 7 = 28."],
    "TNR811_1_06": ["Quelle est la prochaine étape ? 3, 6, 9, 12, __", "Comptez de 3 à 3.", ["13", "14", "15", "16"], "Compter par 3 : 3, 6, 9, 12, 15."],
    "TNR811_1_07": ["Quel est le double de 15 ?", "Double signifie multiplier par 2.", ["25", "28", "30", "35"], "Double 15 = 15 × 2 = 30."],
    "TNR811_1_08": ["Combien font 5 × 8 ?", "Pensez à 5 groupes de 8.", ["35", "45", "40", "48"], "5 × 8 = 40."],
    "TNR811_1_09": ["Nombre de 4 : 4, 8, 12, __, 20. Combien manque-t-il ?", "Combien font 12 + 4 ?", ["14", "16", "15", "18"], "Compter par 4 : 4, 8, 12, 16, 20."],
    "TNR811_1_10": ["Combien font 3 × 9 ?", "Pensez à 3 groupes de 9.", ["24", "27", "21", "29"], "3 × 9 = 27."],
    "TNR811_1_11": ["Quel est le double de 25 ?", "Double signifie ×2.", ["45", "50", "55", "40"], "Double 25 = 25 × 2 = 50."],
    "TNR811_1_12": ["Combien font 4×8 ?", "Pensez à 4 groupes de 8.", ["28", "30", "32", "36"], "4 × 8 = 32."],
    "TNR811_1_13": ["Nombre à partir de 6 : 6, 12, 18, __, 30. Combien manque-t-il ?", "Combien font 18 + 6 ?", ["22", "26", "24", "20"], "Compter par 6 : 6, 12, 18, 24, 30."],
    "TNR811_1_14": ["Combien font 5 × 9 ?", "Pensez à 5 groupes de 9.", ["40", "50", "45", "54"], "5 × 9 = 45."],
    "TNR811_1_15": ["Quel est le double de 12 ?", "Double signifie ×2.", ["22", "24", "20", "26"], "Double 12 = 12 × 2 = 24."],
    "TNR811_1_16": ["Combien font 3 × 7 ?", "Pensez à 3 groupes de 7.", ["18", "24", "21", "28"], "3 × 7 = 21."],
    "TNR811_1_17": ["Nombre à partir de 3 : 3, 6, 9, 12, 15, __. Quelle est la prochaine étape ?", "Récupérez-en 3 à chaque étape.", ["16", "17", "18", "19"], "Compter par 3 : 3, 6, 9, 12, 15, 18."],
    "TNR811_1_18": ["Combien font 4×9 ?", "Pensez à 4 groupes de 9.", ["32", "36", "40", "27"], "4 × 9 = 36."],
    "TNR811_1_19": ["Quel est le double de 35 ?", "Double signifie ×2.", ["60", "65", "70", "75"], "Double 35 = 35 × 2 = 70."],
    "TNR811_1_20": ["Combien font 5 × 7 ?", "Pensez à 5 groupes de 7.", ["30", "35", "40", "42"], "5 × 7 = 35."],
    "TNR811_2_01": ["Quelle est la moitié de 48 ?", "La moitié signifie ÷2.", ["20", "22", "24", "28"], "La moitié de 48 = 48 ÷ 2 = 24."],
    "TNR811_2_02": ["Quel est le triple de 9 ?", "Triple signifie ×3.", ["18", "27", "24", "21"], "Triple 9 = 9 × 3 = 27."],
    "TNR811_2_03": ["Chaîne : 2, 4, 3, 6, 5, 10, 9, __. La règle alterne : doubler, puis soustraire 1. Quelle est la prochaine étape ?", "9 vient après une étape de soustraction. Quelle opération est la prochaine ?", ["10", "18", "8", "12"], "Le motif alterne entre ×2 et −1. Après 9 on double : 9 × 2 = 18."],
    "TNR811_2_04": ["Quelle est la moitié de 64 ?", "La moitié signifie ÷2.", ["30", "34", "32", "36"], "La moitié de 64 = 64 ÷ 2 = 32."],
    "TNR811_2_05": ["Quel est le triple de 12 ?", "Triple signifie ×3.", ["24", "30", "36", "48"], "Triple 12 = 12 × 3 = 36."],
    "TNR811_2_06": ["Chaîne : 1, 3, 2, 6, 5, 15, 14, __. La règle alterne : ×3, puis −1. Quelle est la prochaine étape ?", "14 vient après la soustraction de 1. Quelle opération vient ensuite ?", ["13", "28", "42", "15"], "Alternance : ×3 et −1. Après 14 on multiplie : 14 × 3 = 42."],
    "TNR811_2_07": ["Combien fait la moitié de 100 ?", "La moitié signifie ÷2.", ["40", "50", "55", "45"], "La moitié de 100 = 100 ÷ 2 = 50."],
    "TNR811_2_08": ["Quel est le triple de 15 ?", "Triple signifie ×3.", ["30", "40", "45", "60"], "Triple 15 = 15 × 3 = 45."],
    "TNR811_2_09": ["Quelle est la prochaine étape ? 80, 40, 20, __", "Chaque numéro est divisé par deux.", ["15", "10", "5", "12"], "Chaque nombre est divisible par 2 : 80, 40, 20, 10."],
    "TNR811_2_10": ["Quelle est la moitié de 36 ?", "La moitié signifie ÷2.", ["16", "18", "20", "14"], "La moitié de 36 = 36 ÷ 2 = 18."],
    "TNR811_2_11": ["Quel est le triple de 20 ?", "Triple signifie ×3.", ["40", "50", "60", "80"], "Triple 20 = 20 × 3 = 60."],
    "TNR811_2_12": ["Chaîne : 1, 2, 4, 5, 10, 11, 22, __. La règle alterne : +1, puis ×2. Quelle est la prochaine étape ?", "22 vient après le double. Quelle opération est la prochaine ?", ["23", "24", "44", "32"], "Alternance : +1 et ×2. Après 22 on ajoute 1 : 22 + 1 = 23."],
    "TNR811_2_13": ["Quelle est la moitié de 56 ?", "La moitié signifie ÷2.", ["24", "26", "28", "30"], "La moitié de 56 = 56 ÷ 2 = 28."],
    "TNR811_2_14": ["Quel est le triple de 8 ?", "Triple signifie ×3.", ["16", "20", "24", "28"], "Triple 8 = 8 × 3 = 24."],
    "TNR811_2_15": ["Quelle est la prochaine étape ? 96, 48, 24, 12, __", "Chaque numéro est divisé par deux.", ["8", "6", "10", "4"], "Chaque nombre est divisible par 2 : 96, 48, 24, 12, 6."],
    "TNR811_2_16": ["Quelle est la moitié de 72 ?", "La moitié signifie ÷2.", ["32", "34", "36", "38"], "La moitié de 72 = 72 ÷ 2 = 36."],
    "TNR811_2_17": ["Quel est le triple de 25 ?", "Triple signifie ×3.", ["50", "65", "75", "100"], "Triple 25 = 25 × 3 = 75."],
    "TNR811_2_18": ["Chaîne : 5, 15, 10, 30, 25, 75, 70, __. La règle alterne : ×3, puis −5. Quelle est la prochaine étape ?", "70 vient après la soustraction de 5. Quelle est la prochaine opération ?", ["65", "140", "210", "105"], "Alternance : ×3 et −5. Après 70 on multiplie : 70 × 3 = 210."],
    "TNR811_2_19": ["Quelle est la moitié de 84 ?", "La moitié signifie ÷2.", ["38", "40", "42", "44"], "La moitié de 84 = 84 ÷ 2 = 42."],
    "TNR811_2_20": ["Quel est le triple de 30 ?", "Triple signifie ×3.", ["60", "90", "100", "120"], "Triple 30 = 30 × 3 = 90."],
    "TNR811_3_01": ["Quelle est la prochaine étape ? 1, 3, 7, 15, 31, __", "Essayez ×2 puis +1.", ["47", "62", "63", "60"], "Règle : ×2 puis +1. 1 → 3, 3 → 7, 7 → 15, 15 → 31, 31 → 63."],
    "TNR811_3_02": ["Quelle est la prochaine étape ? 2, 6, 18, 54, __", "Chaque nombre est ×3.", ["108", "162", "72", "60"], "Chaque nombre est multiplié par 3 : 2, 6, 18, 54, 162."],
    "TNR811_3_03": ["Quelle est la prochaine étape ? 100, 97, 91, 82, 70, __", "Regardez les différences : −3, −6, −9, −12...", ["58", "55", "52", "60"], "Les différences augmentent par 3 : −3, −6, −9, −12, −15. Donc 70 − 15 = 55."],
    "TNR811_3_04": ["Quelle est la prochaine étape ? 3, 4, 6, 10, 18, __", "Regardez les différences : 1, 2, 4, 8... elles doublent.", ["26", "34", "28", "36"], "Les différences sont doublées : +1, +2, +4, +8, +16. Donc 18 + 16 = 34."],
    "TNR811_3_05": ["Quelle est la prochaine étape ? 2, 5, 11, 23, 47, __", "Essayez ×2 puis +1.", ["94", "95", "93", "96"], "Règle : ×2 puis +1. 2 → 5, 5 → 11, 11 → 23, 23 → 47, 47 → 95."],
    "TNR811_3_06": ["Quelle est la prochaine étape ? 256, 128, 64, 32, __", "Chaque numéro est divisé par deux.", ["24", "16", "8", "20"], "Chaque nombre est divisible par 2 : 256, 128, 64, 32, 16."],
    "TNR811_3_07": ["Quelle est la prochaine étape ? 1, 4, 13, 40, __", "Essayez ×3 puis +1.", ["80", "120", "121", "81"], "Règle : ×3 puis +1. 1 → 4, 4 → 13, 13 → 40, 40 → 121."],
    "TNR811_3_08": ["Quelle est la prochaine étape ? 50, 46, 40, 32, 22, __", "Les différences se sont accentuées : −4, −6, −8, −10...", ["10", "12", "14", "8"], "Les différences augmentent par 2 : −4, −6, −8, −10, −12. Donc 22 − 12 = 10."],
    "TNR811_3_09": ["Quelle est la prochaine étape ? 3, 9, 27, 81, __", "Chaque nombre est ×3.", ["162", "243", "108", "100"], "Chaque nombre est multiplié par 3 : 3, 9, 27, 81, 243."],
    "TNR811_3_10": ["Quelle est la prochaine étape ? 2, 3, 5, 9, 17, __", "Les écarts sont doublés : +1, +2, +4, +8...", ["25", "33", "34", "31"], "Les différences sont doublées : +1, +2, +4, +8, +16. Donc 17 + 16 = 33."],
    "TNR811_3_11": ["Quelle est la prochaine étape ? 1, 5, 13, 29, __", "Essayez ×2 puis +3.", ["57", "58", "61", "45"], "Règle : ×2 puis +3. 1 → 5, 5 → 13, 13 → 29, 29 → 61."],
    "TNR811_3_12": ["Quelle est la prochaine étape ? 200, 195, 185, 170, 150, __", "Les écarts augmentent : −5, −10, −15, −20...", ["130", "125", "120", "135"], "Les différences augmentent par 5 : −5, −10, −15, −20, −25. Donc 150 − 25 = 125."],
    "TNR811_3_13": ["Quelle est la prochaine étape ? 4, 16, 64, 256, __", "Chaque nombre est ×4.", ["512", "1024", "768", "640"], "Chaque nombre est multiplié par 4 : 4, 16, 64, 256, 1024."],
    "TNR811_3_14": ["Quelle est la prochaine étape ? 1, 2, 6, 24, 120, __", "Multipliez par 2, puis 3, puis 4, puis 5...", ["240", "600", "720", "360"], "×2, ×3, ×4, ×5, ×6. Donc 120 × 6 = 720. C'est ce qu'on appelle des factorielles."],
    "TNR811_3_15": ["Quelle est la prochaine étape ? 5, 8, 14, 26, 50, __", "Les écarts sont doublés : +3, +6, +12, +24...", ["74", "98", "76", "100"], "Les écarts sont doublés : +3, +6, +12, +24, +48. Donc 50 + 48 = 98."],
    "TNR811_3_16": ["Quelle est la prochaine étape ? 3, 10, 31, 94, __", "Essayez ×3 puis +1.", ["188", "282", "283", "281"], "Règle : ×3 puis +1. 3 → 10, 10 → 31, 31 → 94, 94 → 283."],
    "TNR811_3_17": ["Quelle est la prochaine étape ? 80, 77, 71, 62, 50, __", "Les écarts augmentent : −3, −6, −9, −12...", ["35", "38", "40", "42"], "Les différences augmentent par 3 : −3, −6, −9, −12, −15. Donc 50 − 15 = 35."],
    "TNR811_3_18": ["Quelle est la prochaine étape ? 1, 2, 4, 8, 16, 32, __", "Chaque numéro est doublé.", ["48", "60", "64", "36"], "Chaque nombre est ×2 : 1, 2, 4, 8, 16, 32, 64."],
    "TNR811_3_19": ["Quelle est la prochaine étape ? 2, 7, 22, 67, __", "Essayez ×3 puis +1.", ["134", "200", "201", "202"], "Règle : ×3 puis +1. 2 → 7, 7 → 22, 22 → 67, 67 → 202."],
    "TNR811_3_20": ["Quelle est la prochaine étape ? 1000, 990, 970, 940, 900, __", "Les écarts se sont accrus : −10, −20, −30, −40...", ["860", "850", "840", "870"], "Les différences augmentent par 10 : −10, −20, −30, −40, −50. Donc 900 − 50 = 850."],
    "TLR811_1_01": ["Tous les chiens sont des animaux. Spot est un chien. Qu’est-ce que Spot ?", "Si Spot est un chien et que tous les chiens sont des animaux…", ["Une plante", "Un animal", "Un oiseau", "Un poisson"], "Tous les chiens sont des animaux. Spot est un chien. Donc Spot est un animal."],
    "TLR811_1_02": ["Toutes les pommes sont des fruits. Tous les fruits sont de la nourriture. S’ensuit-il que toutes les pommes sont de la nourriture ?", "La chaîne est la suivante : pommes → fruits → nourriture.", ["Oui", "Non", "Juste quelques", "Nous ne pouvons pas savoir"], "Les pommes sont des fruits et les fruits sont de la nourriture. Donc toutes les pommes sont de la nourriture."],
    "TLR811_1_03": ["Tom est plus grand que Sam. Sam est plus grand que Ben. Qui est le plus grand ?", "Mets-les par ordre de taille.", ["Sam", "Ben", "Tom", "Ils sont égaux"], "Tom > Sam > Ben. Tom est le plus grand."],
    "TLR811_1_04": ["Tous les chats ont une queue. Whiskers est un chat. Les moustaches ont-elles une queue ?", "Si tous les chats ont une queue et que Whiskers est un chat…", ["Oui", "Non", "Peut-être", "Seulement parfois"], "Tous les chats ont une queue. Whiskers est un chat. Donc Moustache a une queue."],
    "TLR811_1_05": ["Ana est plus âgée que Ben. Ben est plus âgé que Cara. Qui est le plus jeune ?", "Classez-les du plus vieux au plus jeune.", ["Ana", "Ben", "Cara", "Ils ont le même âge"], "Ana > Ben > Cara selon l'âge. Cara est la plus jeune."],
    "TLR811_1_06": ["Tous les oiseaux ont des plumes. Une hirondelle est un oiseau. L'hirondelle a-t-elle des plumes ?", "Si tous les oiseaux avaient des plumes…", ["Non", "Oui", "Seulement en hiver", "Peut-être"], "Tous les oiseaux ont des plumes. L'hirondelle est un oiseau. Il a donc des plumes."],
    "TLR811_1_07": ["Le rouge est plus gros que le bleu. Le bleu est plus grand que le vert. Quel est le plus petit ?", "Triez-les par taille.", ["Rouge", "Bleu", "Vert", "Ils sont égaux"], "Rouge > Bleu > Vert. Le vert est le plus petit."],
    "TLR811_1_08": ["Tous les poissons vivent dans l'eau. Un poisson rouge est un poisson. Où vit un poisson rouge ?", "Si tous les poissons vivaient dans l’eau…", ["Sur la terre ferme", "Dans les arbres", "Dans l'eau", "dans le ciel"], "Tous les poissons vivent dans l'eau. Les poissons rouges sont des poissons. Il vit donc dans l'eau."],
    "TLR811_1_09": ["Le livre A a plus de pages que le livre B. Le livre B a plus de pages que le livre C. Lequel a le moins de pages ?", "Triez les livres par nombre de pages.", ["Livre A", "Livre B", "Livre C", "Ils sont égaux"], "A > B > C aux pages. Le livre C contient le moins de pages."],
    "TLR811_1_10": ["Tous les carrés ont 4 côtés. Cette forme est un carré. Combien de côtés a-t-il ?", "Si c'est carré...", ["3", "4", "5", "6"], "Tous les carrés ont 4 côtés. Cette forme est carrée. Il a donc 4 côtés."],
    "TLR811_1_11": ["La pizza est moins chère que le steak. Le steak est moins cher que le homard. Quel est le moins cher ?", "Triez-les par prix.", ["Bifteck", "Le homard", "Pizzas", "Ça coûte le même prix"], "Pizza < Steak < Homard à un prix. La pizza est la moins chère."],
    "TLR811_1_12": ["Toutes les roses sont des fleurs. Toutes les fleurs sont des plantes. La rose est-elle une plante ?", "La chaîne suit : roses → fleurs → plantes.", ["Oui", "Non", "Peut-être", "Seulement des roses rouges"], "Les roses sont des fleurs et les fleurs sont des plantes. La rose est donc une plante."],
    "TLR811_1_13": ["L’équipe A a marqué plus que l’équipe B. L’équipe B a marqué plus que l’équipe C. Qui a marqué le plus ?", "Classez les équipes par score.", ["Équipe C", "Équipe B", "Équipe A", "Égalité"], "A > B > C sur la partition. L'équipe A a marqué le plus."],
    "TLR811_1_14": ["Toutes les pièces sont rondes. Un centime est une pièce de monnaie. Quelle forme a un sou ?", "Si toutes les pièces étaient rondes…", ["Carré", "Triangle", "Rond", "Ovale"], "Toutes les pièces sont rondes. Le centime est une monnaie. Donc c'est rond."],
    "TLR811_1_15": ["Mia court plus vite que Lily. Lily court plus vite que Zoé. Qui est la plus lente ?", "Classe-les par vitesse.", ["Mia", "Lily", "Zoé", "Elles sont égales"], "Mia > Lily > Zoé en vitesse. Zoé est la plus lente."],
    "TLR811_1_16": ["Tous les triangles ont 3 côtés. Cette forme a 3 côtés. Est-ce que ça peut être un triangle ?", "Les triangles ont 3 côtés. Cela signifie-t-il nécessairement que la forme est un triangle ?", ["Oui, ça peut être", "Non, jamais", "Seulement si c'est gros", "Seulement si c'est rouge"], "Tous les triangles ont 3 côtés, et cette forme a 3 côtés, elle peut donc être un triangle."],
    "TLR811_1_17": ["Un éléphant est plus lourd qu'un cheval. Un cheval est plus lourd qu'un chien. Quel est le plus simple ?", "Triez-les par poids.", ["L'éléphant", "Le cheval", "Le chien", "je chante pareil"], "Éléphant > Cheval > Chien en poids. Le chien est le plus simple."],
    "TLR811_1_18": ["Tous les crayons peuvent écrire. C'est un crayon. Peut-il écrire ?", "Si tous les crayons pouvaient écrire…", ["Oui", "Non", "Seulement parfois", "Nous ne savons pas"], "Tous les crayons peuvent écrire. C'est un crayon. Pour qu'il puisse écrire."],
    "TLR811_1_19": ["La case A est plus large que la case B. La case B est plus large que la case C. Laquelle est la plus large ?", "Classe-les par largeur.", ["Case C", "Case B", "Case A", "Elles sont égales"], "A > B > C en largeur. La case A est la plus large."],
    "TLR811_1_20": ["Toutes les glaces sont froides. C'est de la glace. est-ce qu'il fait froid", "Si toute la glace est froide…", ["Non", "Peut-être", "Oui", "Seulement en hiver"], "Toutes les glaces sont froides. C'est de la glace. Donc il fait froid."],
    "TLR811_2_01": ["Tout le chocolat est sucré. Ce bonbon est sucré. Le chocolat est-il SÛR ?", "Juste parce que tout le chocolat est sucré, cela signifie-t-il que tout ce qui est sucré est du chocolat ?", ["Oui, bien sûr", "Non, pas nécessairement", "Juste du chocolat noir", "Toujours"], "Tout le chocolat est sucré, mais d’autres choses peuvent aussi l’être. Ce n'est pas nécessairement du chocolat."],
    "TLR811_2_02": ["Anna est plus grande que Ben. Ben est plus grand que Cara. Cara est plus grande que Dan. Qui est le deuxième plus grand ?", "Mettez les quatre par ordre de hauteur.", ["Anna", "Ben", "Cara", "Dan"], "Anna > Ben > Cara > Dan. Ben est le deuxième plus grand."],
    "TLR811_2_03": ["Toutes les voitures ont des roues. Ce véhicule a des roues. Une voiture est-elle SÉCURISÉE ?", "Seules les voitures ont des roues ?", ["Oui", "Non, pas nécessairement", "Seulement si c'est rouge", "Toujours"], "De nombreux véhicules sont équipés de roues (vélos, bus, camions). Ce n'est pas nécessairement une voiture."],
    "TLR811_2_04": ["Le rouge est plus gros que le bleu. Le bleu est plus grand que le vert. Le vert est plus gros que le jaune. Quel est le troisième plus grand ?", "Triez les quatre par taille.", ["Rouge", "Bleu", "Vert", "Jaune"], "Rouge > Bleu > Vert > Jaune. Le vert est le troisième plus grand."],
    "TLR811_2_05": ["Tous les carrés sont des rectangles. Cette forme est un rectangle. Est-ce SÛR carré ?", "Tous les carrés sont des rectangles, mais tous les rectangles sont-ils des carrés ?", ["Oui", "Non, pas nécessairement", "Seulement si c'est petit", "Toujours"], "Tous les carrés sont des rectangles, mais tous les rectangles ne sont pas des carrés. Ce n’est peut-être pas carré."],
    "TLR811_2_06": ["Kim a obtenu 90 points. Lee 85. Min 95. Pat 80. Qui était deuxième ?", "Trier du score le plus élevé au plus bas.", ["Kim", "Lee", "Min.", "Lit"], "Min (95) > Kim (90) > Lee (85) > Pat (80). Kim était deuxième."],
    "TLR811_2_07": ["Tous les chiens aboient. Un animal aboie. Est-ce un chien SÛR ?", "Est-ce que seuls les chiens aboient ?", ["Oui, bien sûr", "Non, pas nécessairement", "Seuls les gros chiens aboient", "Toujours"], "D'autres animaux peuvent également aboyer (par exemple les phoques). Ce n'est pas nécessairement un chien."],
    "TLR811_2_08": ["Le livre A compte 200 pages. B vaut 150. C vaut 300. D vaut 250. Quel est le troisième plus long ?", "Triez du plus grand nombre de pages au moins.", ["Livre A", "Livre B", "Livre C", "Livre D"], "C (300) > D (250) > A (200) > B (150). Le livre A est le troisième plus long."],
    "TLR811_2_09": ["Tous les nombres pairs sont exactement divisibles par 2. Le nombre 15 n’est pas exactement divisible par 2. Que dire de 15 ?", "S'il n'est pas divisible par 2, peut-il être pair ?", ["C'est même", "Ce ne sont pas des cheveux", "Nous ne pouvons pas savoir", "Cela peut être même"], "Tous les nombres pairs sont divisibles par 2. 15 n’est pas divisible par 2. Donc 15 n’est pas pair."],
    "TLR811_2_10": ["Amy, Ben, Cat et Dan courent. Amy bat Ben. Cat surpasse Amy. Dan bat Cat. Qui gagne?", "Si Dan bat Cat et que Cat bat Amy…", ["Amy", "Ben", "Chat", "Dan"], "Dan > Chat > Amy > Ben. Dan gagne."],
    "TLR811_2_11": ["Tous les vélos ont 2 roues. Ce véhicule a 2 roues. Le vélo est-il SÉCURISÉ ?", "Seuls les vélos ont 2 roues ?", ["Oui", "Non, pas nécessairement", "VTT uniquement", "Toujours"], "Et les scooters, les motos ont 2 roues. Ce n'est pas nécessairement un vélo."],
    "TLR811_2_12": ["Quatre amis ont des scores différents : 70, 80, 90, 100. James a obtenu plus de 80 mais moins de 100. Quel était son score ?", "Quel score est compris entre 80 et 100 ?", ["70", "80", "90", "100"], "Le seul score entre 80 et 100 est 90."],
    "TLR811_2_13": ["Toutes les araignées ont 8 pattes. Cette créature a 8 pattes. Est-ce une araignée SÛRE ?", "Seules les araignées ont 8 pattes ?", ["Oui", "Non, pas nécessairement", "Seulement les grands", "Toujours"], "Et les scorpions ont 8 pattes. 8 pattes ne signifie pas nécessairement une araignée."],
    "TLR811_2_14": ["Le chêne est plus grand que le bouleau. Le pin est plus grand que le chêne. L'orme est plus court que le bouleau. Quel arbre est le plus grand ?", "Disposez les quatre arbres.", ["Le chêne", "Le bouleau", "Le pin", "L'orme"], "Pin > Chêne > Bouleau > Orme. Le pin est le plus haut."],
    "TLR811_2_15": ["Toutes les planètes tournent autour d’une étoile. La Terre tourne autour d'une étoile. Cela prouve-t-il que la Terre est une planète ?", "Est-ce que seules les planètes tournent autour des étoiles ?", ["Oui, ça le prouve", "Non, ça ne le prouve pas", "Seulement parfois", "Toujours"], "Et les comètes, les astéroïdes gravitent autour des étoiles. L'orbite à elle seule ne prouve pas que c'est une planète."],
    "TLR811_2_16": ["Sam a plus d'autocollants que Mia. Mia a plus que Jo. Jo a plus que Lee. Qui en a le moins ?", "Commandez-les.", ["Sam", "Mia", "Jo", "Lee"], "Sam > Mia > Jo > Lee. Lee en a le moins."],
    "TLR811_2_17": ["S'il pleut, le sol est mouillé. Le sol est mouillé. Est-ce qu'il pleut, SÛR ?", "Le sol pourrait-il être humide pour d’autres raisons ?", ["Oui, bien sûr", "Non, pas nécessairement", "Seulement en été", "Toujours"], "Quelqu'un aurait pu l'arroser. Un sol humide ne prouve pas la pluie."],
    "TLR811_2_18": ["Le chat pèse moins que le chien. Le chien moins que le mouton. Le mouton moins que la vache. Quel animal pèse le plus ?", "Trier par poids.", ["Le chat", "Le chien", "Le mouton", "La vache"], "Chat < Chien < Mouton < Vache. La vache pèse le plus."],
    "TLR811_2_19": ["Toutes les pommes sont des fruits. Ce n'est PAS un fruit. Est-ce que ça peut être de la pomme ?", "Si toutes les pommes sont des fruits et que celle-ci n'est pas un fruit...", ["Oui", "Non, ça ne peut pas", "Peut-être", "Seulement les verts"], "Toutes les pommes sont des fruits. Si ce n’est pas un fruit, ce ne peut pas être une pomme."],
    "TLR811_2_20": ["Quatre enfants ont 8, 9, 10, 11 ans. Kai est plus grand que Zoé. Zoé que Léo. Léo qu'Ivy. quel âge a Zoé", "Kai est l'aîné, puis Zoe, Leo et Ivy.", ["8", "9", "10", "11"], "Kai=11, Zoé=10, Léo=9, Ivy=8. Zoé a 10 ans."],
    "TLR811_3_01": ["S'il pleut, Tom prend un parapluie. S'il prend un parapluie, il reste au sec. Il pleut. Tom restera-t-il au sec ?", "La chaîne suit : pluie → parapluie → sec.", ["Oui", "Non", "Peut-être", "Seulement s'il fait froid"], "Pluie → parapluie → sec. Il pleut, donc Tom reste au sec."],
    "TLR811_3_02": ["Si A est vrai, alors B est vrai. B n'est PAS vrai. Est-ce que A est vrai ?", "Si A rendait toujours B vrai et B faux...", ["Oui", "Non", "Peut-être", "Nous ne pouvons pas savoir"], "Si A était vrai, B devrait l’être. Mais B ne l’est pas. Donc A ne peut pas être vrai."],
    "TLR811_3_03": ["Aujourd'hui c'est mercredi. Quel jour était-on il y a 3 jours ?", "Compte à rebours : mardi, lundi, dimanche.", ["lundi", "dimanche", "samedi", "mardi"], "Mercredi −1 = mardi, −2 = lundi, −3 = dimanche."],
    "TLR811_3_04": ["Si vous étudiez, vous réussissez le test. Si vous réussissez le test, vous obtenez la récompense. Maya a appris. Maya obtient-elle sa récompense ?", "L'enchaînement est le suivant : apprentissage → réussite du test → récompense.", ["Oui", "Non", "Seulement parfois", "Nous ne pouvons pas savoir"], "Apprentissage → réussite → récompense. Maya a appris, alors elle reçoit la récompense."],
    "TLR811_3_05": ["Si Anna nage, elle porte des lunettes de natation. Anna ne porte PAS de lunettes. Anna nage-t-elle ?", "S'il porte toujours des lunettes lorsqu'il nage, et maintenant il ne le fait plus...", ["Oui", "Non", "Peut-être", "Lundi seulement"], "S'il nageait, il porterait des lunettes. Il ne transporte pas, donc il ne nage pas."],
    "TLR811_3_06": ["Nous sommes aujourd’hui le 28 mars. Quelle date est dans 5 jours ?", "Mars compte 31 jours. Comptez à partir de 28.", ["33 mars", "1er avril", "2 avril", "3 avril"], "Mars compte 31 jours. 28 + 5 = 33. 33 − 31 = 2. Nous sommes donc le 2 avril."],
    "TLR811_3_07": ["Si Max mange du gâteau, il tombe malade. Max n'est PAS blessé. Max a-t-il mangé du gâteau ?", "Si le gâteau le rend toujours malade, et maintenant il ne le fait plus...", ["Oui", "Non", "Peut-être", "Juste un gâteau au chocolat"], "S'il mangeait du gâteau, il serait malade. Il n’en a pas envie, alors il n’a pas mangé."],
    "TLR811_3_08": ["Si A mène à B, B à C, C à D. Est-ce que A arrive. Est-ce que D arrive ?", "La chaîne de A à D suit.", ["Oui", "Non", "Seulement parfois", "Nous ne pouvons pas savoir"], "A → B → C → D. Si A, alors D."],
    "TLR811_3_09": ["Nous sommes en octobre. Combien de mois reste-t-il avant mars (en comptant) ?", "Numéro : novembre, décembre, janvier, février, mars.", ["4", "5", "6", "3"], "Novembre (1), décembre (2), janvier (3), février (4), mars (5). Cela fait 5 mois."],
    "TLR811_3_10": ["Si une forme a 4 côtés égaux et 4 angles droits, elle est carrée. Cette forme n’a PAS 4 côtés égaux. Bien sûr, ce n'est PAS carré ?", "Peut-il s'agir d'un carré sans 4 côtés égaux ?", ["Oui, ce n'est pas carré", "Non, ça pourrait toujours être carré", "Peut-être", "Seulement si c'est gros"], "Le carré doit avoir 4 côtés égaux. S'il n'y en a pas, ce n'est pas carré."],
    "TLR811_3_11": ["Si vous appuyez sur le bouton, la lumière s'allume. Si la lumière s'allume, la cloche sonne. Vous avez appuyé sur le bouton. que se passe-t-il", "La chaîne suit : bouton → lumière → cloche.", ["Rien", "Juste la lumière", "La cloche sonne", "Le bouton casse"], "Bouton → lumière → cloche. Vous avez appuyé, alors la cloche sonne."],
    "TLR811_3_12": ["Aujourd'hui, nous sommes vendredi. Quel jour sera-ce dans 10 jours ?", "10 = 7 + 3. Une semaine entière plus 3 jours.", ["dimanche", "lundi", "mardi", "mercredi"], "10 jours = 1 semaine + 3 jours. Vendredi + 3 = lundi."],
    "TLR811_3_13": ["Tous les élèves de la classe A jouent au football. Tom ne joue PAS au football. Tom est-il en classe A ?", "Si tout le monde en A joue au football et que Tom ne le fait pas…", ["Oui", "Non", "Peut-être", "Uniquement le week-end"], "Tout le monde en A joue au football. Tom ne joue pas, donc il n'est pas en classe A."],
    "TLR811_3_14": ["S'il neige, l'école est fermée. Si l'école est fermée, les enfants jouent dehors. Il n'a PAS neigé. Pouvons-nous être SÛRS que les enfants ne jouent PAS dehors ?", "L'école pourrait-elle fermer pour une autre raison ?", ["Oui, nous en sommes sûrs", "Non, nous ne pouvons pas en être sûrs", "Seulement en été", "Toujours"], "L'école peut également fermer pour d'autres raisons (vacances, réparations). Les enfants pouvaient encore jouer dehors."],
    "TLR811_3_15": ["Nous sommes le 30 novembre. Quelle date est dans 3 jours ?", "Novembre a 30 jours ; quelle est la prochaine étape après le 30 novembre ?", ["33 novembre", "1er décembre", "2 décembre", "3 décembre"], "Novembre a 30 jours. 30 novembre +1 = 1 décembre, +2 = 2 décembre, +3 = 3 décembre"],
    "TLR811_3_16": ["X est plus grand que Y. Y que Z. Z que W. W que V. Lequel est plus grand ?", "Qui est au sommet de la chaîne ?", ["V", "w", "Oui", "X"], "X > Y > Z > W > V. X est le plus grand."],
    "TLR811_3_17": ["Tous les poissons savent nager. Quelque chose ne sait pas nager. est-ce du poisson", "Si tous les poissons nagent et que ce n’est pas le cas…", ["Oui", "Non", "Peut-être", "Seulement des petits poissons"], "Tous les poissons nagent. S'il ne sait pas nager, ce n'est pas un poisson."],
    "TLR811_3_18": ["aujourd'hui, c'est mardi .. Quel jour sera-ce dans 25 jours ?", "25 ÷ 7 = 3 semaines et 4 jours supplémentaires.", ["vendredi", "samedi", "dimanche", "lundi"], "25 = 3 semaines + 4 jours. Mardi + 4 = samedi."],
    "TLR811_3_19": ["Si A est vrai, B doit être vrai. Si B est vrai, C doit être vrai. C'est PAS vrai. Est-ce que A est vrai ?", "Cela fonctionne dans l’autre sens : si C est faux, qu’en est-il de B ? Alors avec A ?", ["Oui", "Non", "Peut-être", "Nous ne pouvons pas savoir"], "Si A → B → C. C est faux, donc B est faux, donc A est faux."],
    "TLR811_3_20": ["Chaque chat est poilu. Tout ce qui est poilu est doux. Tout ce qui est doux est agréable à câliner. Whiskers est un chat. Est-ce agréable de serrer les moustaches dans ses bras ?", "La chaîne suit : chat → poilu → doux → câlinable.", ["Oui", "Non", "Peut-être", "Seulement les chatons"], "Chat → poilu → doux → gentil. Whiskers est un chat, donc c'est agréable de le serrer dans ses bras."],
    "TSR811_1_01": ["Combien de faces a un cube ?", "Pensez à un dé : comptez les faces plates.", ["4", "6", "8", "12"], "Un cube possède 6 faces planes."],
    "TSR811_1_02": ["Combien d’arêtes possède un cube ?", "Une arête est l'endroit où deux faces se rencontrent. Comptez tous les bords.", ["6", "8", "10", "12"], "Un cube a 12 arêtes."],
    "TSR811_1_03": ["Combien de sommets (coins) possède un cube ?", "Un sommet est le point de rencontre des arêtes.", ["4", "6", "8", "12"], "Un cube a 8 sommets (coins)."],
    "TSR811_1_04": ["Quelle forme a chaque face d’un cube ?", "Toutes les faces du cube ont la même forme.", ["Triangle", "Rectangulaire", "Carré", "Cercle"], "Chaque face d'un cube est un carré."],
    "TSR811_1_05": ["Combien de faces possède une boîte rectangulaire (cuboïde) ?", "Pensez à une boîte à chaussures. Comptez les visages plats.", ["4", "5", "6", "8"], "Un cuboïde (boîte rectangulaire) a 6 faces."],
    "TSR811_1_06": ["Combien de faces planes possède une sphère ?", "Une sphère est comme une balle.", ["0", "1", "2", "4"], "Une sphère a 0 faces planes. Il est complètement arrondi."],
    "TSR811_1_07": ["Combien de faces planes un cylindre possède-t-il ?", "Pensez à une boîte de conserve. Quels côtés plats a-t-il ?", ["0", "1", "2", "3"], "Un cylindre possède 2 faces planes (cercle supérieur et cercle inférieur)."],
    "TSR811_1_08": ["Quelle forme 3D a 6 faces carrées, toutes identiques ?", "Toutes les faces sont des carrés identiques.", ["Cuboïde", "Cubes", "Prisme", "Pyramide"], "Un cube possède 6 faces carrées identiques."],
    "TSR811_1_09": ["Combien de faces planes un cône a-t-il ?", "Pensez à un cornet de glace. Il possède une seule base plate.", ["0", "1", "2", "3"], "Un cône a 1 face plate (base circulaire)."],
    "TSR811_1_10": ["Combien d’arêtes possède une pyramide triangulaire (tétraèdre) ?", "Il possède 4 faces triangulaires. Comptez où les triangles se rencontrent.", ["4", "5", "6", "8"], "Une pyramide triangulaire (tétraèdre) possède 6 arêtes."],
    "TSR811_1_11": ["Si vous regardez un cube directement devant vous, quelle forme voyez-vous ?", "Visualisez une face du cube avant.", ["Triangle", "Cercle", "Carré", "Rectangulaire"], "En regardant directement une face d’un cube, vous voyez un carré."],
    "TSR811_1_12": ["Combien de faces possède un prisme triangulaire ?", "Pensez à une boîte Toblerone – 2 triangles et quelques rectangles.", ["3", "4", "5", "6"], "Un prisme triangulaire a 5 faces : 2 triangles et 3 rectangles."],
    "TSR811_1_13": ["Combien de sommets possède une pyramide triangulaire (tétraèdre) ?", "Comptez les angles vifs.", ["3", "4", "5", "6"], "Une pyramide triangulaire a 4 sommets."],
    "TSR811_1_14": ["Quelle est la forme de la base d'un cône ?", "La base plate d’un cône est…", ["Carré", "Triangle", "Cercle", "Ovale"], "La base d'un cône est un cercle."],
    "TSR811_1_15": ["Combien d’arêtes possède un cuboïde ?", "Un cuboïde est comme un cube, mais avec des faces rectangulaires. Comptez les bords.", ["8", "10", "12", "14"], "Un cuboïde a 12 arêtes, tout comme un cube."],
    "TSR811_1_16": ["Combien de faces possède une pyramide à base carrée ?", "Il possède une base carrée et des faces latérales triangulaires.", ["4", "5", "6", "8"], "Une pyramide à base carrée a 5 faces : 1 base carrée et 4 triangles."],
    "TSR811_1_17": ["Si vous empilez 2 cubes l’un sur l’autre, la forme combinée ressemble le plus à un…", "Deux cubes empilés forment une forme plus haute.", ["Cubes", "Sphères", "Cuboïde", "Cylindre"], "Deux cubes empilés forment un cuboïde (boîte rectangulaire)."],
    "TSR811_1_18": ["Combien de sommets possède un cuboïde ?", "Comptez tous les coins d'une boîte rectangulaire.", ["4", "6", "8", "10"], "Un cuboïde a 8 sommets, tout comme un cube."],
    "TSR811_1_19": ["Combien de surfaces courbes possède une sphère ?", "Une sphère est parfaitement ronde partout.", ["0", "1", "2", "4"], "Une sphère a 1 surface courbe."],
    "TSR811_1_20": ["Combien de faces possède un prisme hexagonal ?", "Il possède 2 extrémités hexagonales et des faces latérales rectangulaires. L'hexagone a 6 côtés.", ["6", "7", "8", "10"], "Un prisme hexagonal a 8 faces : 2 hexagones + 6 rectangles."],
    "TSR811_2_01": ["Si vous coupez un cube exactement en deux, parallèlement à l’une des faces, quelle forme aura la section ?", "Couper droit, comme couper du pain.", ["Triangle", "Cercle", "Carré", "Rectangulaire"], "Couper le cube parallèlement à une face vous donne une section de forme carrée."],
    "TSR811_2_02": ["8 petits cubes forment un cube 2×2×2. Combien de petits cubes sont complètement cachés (sans aucune face visible) ?", "Dans la disposition 2×2×2, chaque cube est à l’extérieur.", ["0", "1", "2", "4"], "Dans le cube 2×2×2, chaque petit cube se trouve au coin avec des faces visibles. Aucun n'est caché."],
    "TSR811_2_03": ["Combien d’arêtes possède un prisme triangulaire ?", "3 bords du triangle supérieur + 3 du bas + 3 les reliant.", ["6", "8", "9", "12"], "Un prisme triangulaire a 9 arêtes : 3 + 3 + 3."],
    "TSR811_2_04": ["Vous alignez 3 cubes les uns après les autres, face à face. Combien de faces des petits cubes sont cachées (touchant un autre cube) ?", "Là où les cubes se touchent, 2 faces sont cachées à chaque jointure.", ["2", "3", "4", "6"], "Il y a 2 articulations. Chacun cache 2 visages. Total des faces cachées : 2 × 2 = 4."],
    "TSR811_2_05": ["Combien d’arêtes possède une pyramide à base carrée ?", "4 bords à la base + 4 vers le haut.", ["5", "6", "8", "10"], "Une pyramide à base carrée possède 8 arêtes : 4 à la base + 4 sur les côtés."],
    "TSR811_2_06": ["Si vous coupez un cylindre en deux (perpendiculairement à la hauteur), quelle forme aura la section ?", "Couper comme une bûche, perpendiculairement à l'axe.", ["Carré", "Rectangulaire", "Cercle", "Ovale"], "En coupant le cylindre perpendiculairement à la hauteur vous obtenez un cercle."],
    "TSR811_2_07": ["27 petits cubes forment un cube 3×3×3. Combien de petits cubes ont au moins une face visible à l’extérieur ?", "Seul le cube exactement au centre est complètement caché.", ["24", "25", "26", "27"], "Un seul cube (celui du centre) est caché. 27 − 1 = 26 cubes ont au moins une face visible."],
    "TSR811_2_08": ["Combien de faces possède un prisme pentagonal ?", "2 têtes pentagonales + faces rectangulaires. Le pentagone a 5 côtés.", ["5", "6", "7", "8"], "Un prisme pentagonal a 7 faces : 2 pentagones + 5 rectangles."],
    "TSR811_2_09": ["Combien de sommets possède une pyramide à base carrée ?", "4 coins à la base + 1 point en haut.", ["4", "5", "6", "8"], "Une pyramide à base carrée possède 5 sommets : 4 à la base + 1 sommet."],
    "TSR811_2_10": ["4 cubes sont placés dans un carré 2×2, en une seule couche. Combien de visages peut-on voir d’en haut ?", "Chaque cube en montre 1 face visible.", ["2", "3", "4", "8"], "Chacun des 4 cubes en montre 1 face visible. Total = 4 faces visibles."],
    "TSR811_2_11": ["Combien de faces a une pyramide hexagonale ?", "1 base hexagonale + faces latérales triangulaires. L'hexagone a 6 côtés.", ["6", "7", "8", "9"], "Une pyramide hexagonale a 7 faces : 1 hexagone + 6 triangles."],
    "TSR811_2_12": ["Si vous coupez un cube d’un bord à l’autre (en diagonale passant par le milieu), la section est un…", "La coupe est en diagonale mais reste plate.", ["Triangle", "Carré", "Rectangulaire", "Cercle"], "Couper d'un bord à l'opposé vous donne une section rectangulaire."],
    "TSR811_2_13": ["Combien de faces possède une pyramide triangulaire (tétraèdre) ?", "Toutes ses faces sont des triangles.", ["3", "4", "5", "6"], "Une pyramide triangulaire possède 4 faces triangulaires."],
    "TSR811_2_14": ["8 cubes forment un cube 2×2×2. Combien de faces des petits cubes sont visibles à l’extérieur du grand cube ?", "Le grand cube possède 6 faces, chacune composée de 4 petites faces.", ["16", "20", "24", "32"], "6 grandes faces × 4 petites faces chacune = 24 petites faces visibles."],
    "TSR811_2_15": ["Combien de sommets possède une pyramide à base pentagonale ?", "5 coins à la base + 1 point en haut.", ["5", "6", "7", "10"], "Une pyramide pentagonale possède 6 sommets : 5 à la base + 1 au sommet."],
    "TSR811_2_16": ["Combien d’arêtes possède un prisme hexagonal ?", "6 haut + 6 bas + 6 les reliant.", ["12", "14", "16", "18"], "Un prisme hexagonal a 18 arêtes : 6 + 6 + 6."],
    "TSR811_2_17": ["Retirez un cube de coin d'un arrangement 2 × 2 × 2. Combien de petits cubes reste-t-il ?", "Vous disposez de 8 petits cubes et en retirez 1.", ["5", "6", "7", "4"], "8 − 1 = il reste 7 cubes."],
    "TSR811_2_18": ["Combien de sommets possède un prisme triangulaire ?", "3 coins à chaque extrémité triangulaire.", ["4", "5", "6", "8"], "Un prisme triangulaire possède 6 sommets : 3 sur chaque triangle."],
    "TSR811_2_19": ["Si vous peignez toutes les faces d’un cube 2×2×2 et que vous le dépliez, combien de petits cubes ont exactement 3 faces peintes ?", "Dans le cube 2×2×2, chaque petit cube est au coin.", ["4", "6", "8", "0"], "Les 8 cubes en 2×2×2 sont des coins, donc tous les 8 ont exactement 3 faces peintes."],
    "TSR811_2_20": ["Combien de faces possède un prisme octogonal ?", "2 extrémités octogonales + faces rectangulaires. L'octogone a 8 côtés.", ["8", "10", "12", "16"], "Un prisme octogonal a 10 faces : 2 octogones + 8 rectangles."],
    "TSR811_3_01": ["Combien de carrés un cube déplie-t-il (la version dépliée) ?", "Chaque face du cube devient un carré qui se déplie.", ["4", "5", "6", "8"], "Un cube a 6 faces, donc déplié il a 6 carrés."],
    "TSR811_3_02": ["Dans un cube 3×3×3 de 27 petits cubes, combien de cubes sont complètement cachés (aucune face visible) ?", "Seul le cube exactement au centre n’est pas tourné vers l’extérieur.", ["0", "1", "4", "8"], "Un seul cube, celui exactement au centre, est complètement caché."],
    "TSR811_3_03": ["Lorsque vous pliez une croix dépliée (comme un plus de 6 carrés), quelle forme 3D obtenez-vous ?", "Déplié en croix, c'est l'un des plus courants pour une forme très connue.", ["Pyramide", "Cuboïde", "Cubes", "Prisme"], "Un entrecroisement de 6 carrés se plie en un cube."],
    "TSR811_3_04": ["Dans un cube 3×3×3, combien de petits cubes ont exactement 3 faces visibles ?", "Les cubes de coin ont 3 faces visibles. Combien de coins a un cube ?", ["4", "6", "8", "12"], "Un cube a 8 coins. Chaque cube de coin a exactement 3 faces visibles."],
    "TSR811_3_05": ["Si vous collez 2 cubes sur une face, combien de faces la nouvelle forme aura-t-elle au total ?", "Chaque cube possède 6 faces, mais 2 sont cachées là où elles sont collées.", ["8", "10", "11", "12"], "6 + 6 = 12 faces au total. Soustrayez 2 faces cachées : 12 − 2 = 10."],
    "TSR811_3_06": ["Dans un cube 3×3×3, combien de petits cubes ont exactement 2 faces visibles ?", "Les cubes sur les bords (et non sur les coins) ont 2 faces visibles. Combien d’arêtes possède un cube ?", ["6", "8", "12", "24"], "Un cube a 12 arêtes. Sur chaque bord il y a 1 cube qui n'est pas un coin. 12 × 1 = 12 cubes à 2 faces."],
    "TSR811_3_07": ["Si vous coupez un cube d’un seul coup droit, combien de morceaux obtenez-vous au maximum ?", "Une seule coupe se divise en 2 parties au maximum.", ["2", "3", "4", "6"], "Une coupe droite dans n'importe quelle forme donne au maximum 2 pièces."],
    "TSR811_3_08": ["Dans un cube 3×3×3, combien de petits cubes ont exactement 1 face visible ?", "Les cubes au centre de chaque face ont 1 face visible. Un cube a 6 faces.", ["4", "6", "8", "12"], "Sur chacune des 6 faces se trouve 1 cube central. 6 × 1 = 6 cubes avec exactement 1 face."],
    "TSR811_3_09": ["De combien de formes se compose le dépliage d'une pyramide à base carrée ?", "Comptez la base triangulaire et les faces.", ["4", "5", "6", "8"], "Il se déplie en 5 formes : 1 carré (base) + 4 triangles (côtés)."],
    "TSR811_3_10": ["Si vous collez 3 cubes à la suite (face à face), combien de faces aura la nouvelle forme ?", "3 cubes = 18 faces au total. Il y a 2 joints, chacun cachant 2 faces.", ["12", "14", "16", "18"], "3 × 6 = 18 faces. 2 jointures × 2 faces cachées = 4 cachées. 18 - 4 = 14."],
    "TSR811_3_11": ["Dans un cube 4×4×4 (64 petits cubes), combien de petits cubes y a-t-il à la surface ?", "Total des cubes moins ceux à l'intérieur. L'intérieur est 2×2×2.", ["48", "52", "56", "60"], "Intérieur = 2×2×2 = 8 cubes. À l'extérieur = 64 − 8 = 56."],
    "TSR811_3_12": ["Si vous peignez un cube 3×3×3 et le divisez en petits cubes, combien n’ont pas de peinture du tout ?", "Seul le cube exactement au centre n’a pas de face peinte.", ["0", "1", "4", "8"], "Seul le cube au centre ne touche pas l'extérieur, il n'a donc pas de peinture."],
    "TSR811_3_13": ["Un filet pour prisme triangulaire a combien de formes ?", "2 extrémités triangulaires + côtés rectangulaires.", ["3", "4", "5", "6"], "Le filet comporte 5 formes : 2 triangles + 3 rectangles."],
    "TSR811_3_14": ["Si vous peignez un cube 2×2×2 et le divisez en 8 petits cubes, combien de 3 faces exactement sont peintes ?", "En 2×2×2, chaque cube est au coin.", ["4", "6", "8", "2"], "Tous les 8 sont au coin, donc tous ont exactement 3 visages peints."],
    "TSR811_3_15": ["En regardant un cube depuis un coin, combien de faces pouvez-vous voir en même temps ?", "D'un coin, on voit les visages s'y rencontrer.", ["1", "2", "3", "4"], "D'un coin du cube, vous voyez au maximum 3 faces."],
    "TSR811_3_16": ["Dans un cube 3×3×3, le nombre total de petites faces visibles à l’extérieur est… ?", "Le grand cube a 6 faces, chacune avec 9 petites faces.", ["36", "48", "54", "27"], "6 grandes faces × 9 petites faces = 54 petites faces visibles."],
    "TSR811_3_17": ["Si vous collez 2 cubes côte à côte et placez le troisième par-dessus un (forme en L), combien de faces la forme a-t-elle ?", "2 cubes collés = 10 faces. Le troisième ci-dessus cache 2 autres visages.", ["12", "14", "16", "18"], "2 cubes collés = 10 faces. Troisième cube : 10 + 6 − 2 = 14 faces."],
    "TSR811_3_18": ["Combien de petits cubes faut-il pour construire un cube 4×4×4 ?", "Multipliez 4 × 4 × 4.", ["16", "32", "48", "64"], "4 × 4 × 4 = 64 petits cubes."],
    "TSR811_3_19": ["Dans un cube 3×3×3, combien de petits cubes partagent une face avec le cube central ?", "Le cube central est touché par les cubes du haut, du bas, de gauche, de droite, de l'avant et de l'arrière.", ["4", "6", "8", "12"], "Le cube central est accessible depuis 6 directions : haut, bas, gauche, droite, avant, arrière."],
    "TSR811_3_20": ["Si vous collez 6 cubes dans un rectangle plat 2×3×1, combien de faces la forme a-t-elle ?", "6 cubes = 36 faces. Compte les jointures internes qui masquent les visages.", ["18", "20", "22", "24"], "6 × 6 = 36 faces. Il y a 7 joints internes (4 horizontaux + 3 verticaux), chacun cachant 2 faces : 36 − 14 = 22."],
    "TMP811_1_01": ["Un agriculteur possède 25 moutons. Tous s’enfuient sauf 9. Combien reste-t-il de moutons ?", "\"Tous sauf 9\" signifie que 9 n'a pas fonctionné.", ["16", "9", "25", "0"], "\"Tous sauf 9 courent\" signifie 9 restent. La réponse est 9."],
    "TMP811_1_02": ["3 amis partagent 12 cookies à parts égales. Combien gagne chacun ?", "Divisez 12 par 3.", ["3", "4", "5", "6"], "12 ÷ 3 = 4 biscuits chacun."],
    "TMP811_1_03": ["Un magasin vend des pommes à 2 £ pièce. Combien coûtent 5 pommes ?", "Multipliez le prix unitaire par le nombre de pommes.", ["7 £", "8 £", "10 £", "12 £"], "5 × 2 £ = 10 £."],
    "TMP811_1_04": ["Combien de mois dans l'année comportent 28 jours ?", "Pensez-y : est-ce que certains mois seulement comportent 28 jours ?", ["1", "6", "12", "2"], "Tous les 12 mois comportent au moins 28 jours !"],
    "TMP811_1_05": ["Un livre comporte 6 chapitres de 10 pages chacun. Combien de pages compte-t-il au total ?", "Multipliez le nombre de chapitres par le nombre de pages par chapitre.", ["16", "50", "60", "66"], "6 × 10 = 60 pages."],
    "TMP811_1_06": ["Vous disposez de 3 boîtes contenant chacune 4 balles. Combien de balles as-tu au total ?", "Multipliez les cases par les boules dans chaque case.", ["7", "9", "12", "15"], "3 × 4 = 12 balles."],
    "TMP811_1_07": ["Dans une course, vous dépassez le deuxième. Où es-tu en ce moment?", "Si vous dépassez celui qui occupe la 2ème place, vous prenez sa place.", ["1ère place", "2ème place", "3ème place", "4ème place"], "Vous êtes à la 2ème place. Vous avez réussi le deuxième, pas le premier."],
    "TMP811_1_08": ["Un boulanger réalise 5 gâteaux par heure. Combien de tortures fait-il en 4 heures ?", "Multipliez les tortures par heure par le nombre d'heures.", ["9", "15", "20", "25"], "5 × 4 = 20 gâteaux."],
    "TMP811_1_09": ["Tom a 8 jouets. Il en reçoit 3 de plus le jour de son anniversaire. Combien a-t-il maintenant ?", "Ajoutez les nouveaux jouets à ce qu'il avait déjà.", ["5", "10", "11", "12"], "8 + 3 = 11 jouets."],
    "TMP811_1_10": ["Qu'est-ce qui pèse le plus : 1 kg de plumes ou 1 kg de pierres ?", "Regardez le poids : les deux font 1 kg.", ["Plumes", "Les pierres", "De même", "Ça dépend"], "Les deux pèsent 1 kg, donc pareil !"],
    "TMP811_1_11": ["Une araignée a 8 pattes. Combien de pattes ont 3 araignées ?", "Multipliez les pattes d'une araignée par le nombre d'araignées.", ["16", "20", "24", "28"], "3 × 8 = 24 pieds."],
    "TMP811_1_12": ["Vous avez 20 bonbons et vous en mangez 3 par jour. Après 4 jours, combien en reste-t-il ?", "Calculez d’abord combien vous avez mangé au total.", ["5", "8", "10", "12"], "4 × 3 = 12 mangés. 20 − 12 = 8 restants."],
    "TMP811_1_13": ["Combien de côtés a un cercle ?", "Un côté est une règle. Le cercle a-t-il des bords droits ?", ["0", "1", "2", "4"], "Un cercle a 0 côté droit."],
    "TMP811_1_14": ["Une voiture a 4 roues. Combien de roues ont 5 voitures ?", "Multipliez les roues d'une voiture par le nombre de voitures.", ["9", "15", "16", "20"], "5 × 4 = 20 roues."],
    "TMP811_1_15": ["Une douzaine d’œufs équivaut à 12. Combien d’œufs font une demi-douzaine ?", "La moitié de 12 est…", ["4", "5", "6", "8"], "Une demi-douzaine = 12 ÷ 2 = 6."],
    "TMP811_1_16": ["Si c'est aujourd'hui votre 9ème anniversaire, combien d'anniversaires avez-vous fêté jusqu'à présent ?", "Le premier anniversaire, c’était quand vous aviez 1 an ; maintenant nous sommes le 9.", ["8", "9", "10", "1"], "9e anniversaire signifie que vous l'avez célébré 9 fois."],
    "TMP811_1_17": ["Une semaine compte 7 jours. Combien de jours y a-t-il dans 3 semaines ?", "Multipliez les jours d'une semaine par le nombre de semaines.", ["10", "14", "21", "28"], "3 × 7 = 21 jours."],
    "TMP811_1_18": ["Vous disposez de 5,00 £ et dépensez 1,50 £. Combien te reste-t-il ?", "Soustrayez ce que vous avez dépensé.", ["2,50 £", "3,00 £", "3,50 £", "4,00 £"], "5,00 £ - 1,50 £ = 3,50 £."],
    "TMP811_1_19": ["4 amis ont chacun 6 balles. Combien de balles ont-ils ensemble ?", "Multipliez le nombre d'amis par les balles de chaque personne.", ["10", "18", "20", "24"], "4 × 6 = 24 balles."],
    "TMP811_1_20": ["Combien de minutes compte une demi-heure ?", "Une heure compte 60 minutes.", ["20", "25", "30", "45"], "La moitié de 60 minutes = 30 minutes."],
    "TMP811_2_01": ["Un escargot parcourt 3 cm en une minute. Jusqu'où va-t-on en 10 minutes ?", "Multipliez la vitesse par le temps.", ["13 cm", "30 cm", "33 cm", "300cm"], "3 × 10 = 30 cm."],
    "TMP811_2_02": ["Dans un carré magique, chaque ligne totalise 15. La première ligne est : 2, ?, 6. Quel est le nombre manquant ?", "2 + ? + 6 = 15.", ["5", "6", "7", "8"], "2 + ? + 6 = 15, alors ? = 15 − 2 − 6 = 7."],
    "TMP811_2_03": ["24 bonbons sont répartis à parts égales entre 6 enfants. Combien gagne chacun ?", "Répartissez les bonbons selon le nombre d'enfants.", ["3", "4", "5", "6"], "24 ÷ 6 = 4 bonbons chacun."],
    "TMP811_2_04": ["Un robinet remplit un seau en 10 minutes. Combien de seaux peut-il remplir en une heure ?", "1 heure = 60 minutes.", ["4", "5", "6", "10"], "60 ÷ 10 = 6 seaux."],
    "TMP811_2_05": ["Dans un carré magique (somme 15), une ligne vaut : 6, 5, ?. Quel est le numéro manquant ?", "6 + 5 + ? = 15.", ["3", "4", "5", "6"], "6 + 5 + ? = 15, alors ? = 15 − 6 − 5 = 4."],
    "TMP811_2_06": ["Un vélo roule à 12 km/h. Quelle distance parcourt-il en 3 heures ?", "Multipliez la vitesse par le temps.", ["15km", "24km", "36km", "48km"], "12 × 3 = 36 km."],
    "TMP811_2_07": ["3 amis trouvent 30 £ et les partagent à parts égales. Combien gagne chacun ?", "Divisez 30 £ par 3.", ["5 £", "10 £", "12 £", "15 £"], "30 £ ÷ 3 = 10 £ chacun."],
    "TMP811_2_08": ["Une usine fabrique 50 jouets par jour. Combien gagne-t-il en 5 jours ?", "Multipliez les jouets par jour par le nombre de jours.", ["55", "100", "200", "250"], "50 × 5 = 250 jouets."],
    "TMP811_2_09": ["Dans un carré magique (somme 15), une ligne vaut : 8, 3, ?. Quel est le numéro manquant ?", "8 + 3 + ? = 15.", ["3", "4", "5", "6"], "8 + 3 + ? = 15, alors ? = 15 − 8 − 3 = 4."],
    "TMP811_2_10": ["Vous achetez 3 produits pour 4,50 £ chacun. Combien payez-vous au total ?", "Multipliez le prix par la quantité.", ["12,00 £", "13,50 £", "14,50 £", "15,00 £"], "3 × 4,50 £ = 13,50 £."],
    "TMP811_2_11": ["Un train roule à 60 km/h. Quelle distance parcourt-il en 2 heures ?", "Multipliez la vitesse par le temps.", ["62km", "90km", "100km", "120km"], "60 × 2 = 120 km."],
    "TMP811_2_12": ["36 pommes sont placées dans des caisses de 9. Combien faut-il de caisses ?", "Divisez 36 par 9.", ["3", "4", "5", "6"], "36 ÷ 9 = 4 cases."],
    "TMP811_2_13": ["Dans un carré magique (somme 15), une ligne vaut : 8, 1, ?. Quel est le numéro manquant ?", "8 + 1 + ? = 15.", ["4", "5", "6", "7"], "8 + 1 + ? = 15, alors ? = 15 − 8 − 1 = 6."],
    "TMP811_2_14": ["Vous avez 20 £. Un livre coûte 3,50 £. Combien de livres pouvez-vous vous permettre d’acheter ?", "Déposez 3,50 £ à plusieurs reprises jusqu'à ce que vous ne puissiez plus le faire.", ["4", "5", "6", "7"], "5 × 3,50 £ = 17,50 £ (assez). 6 × 3,50 £ = 21,00 £ (trop). Vous pouvez en acheter 5."],
    "TMP811_2_15": ["Un tuyau d'arrosage remplit 2 litres par minute. Combien de litres en 15 minutes ?", "Multipliez le débit par le temps.", ["17", "25", "30", "32"], "2 × 15 = 30 litres."],
    "TMP811_2_16": ["5 enfants se partagent à parts égales 35 autocollants. Combien gagne chacun ?", "Divisez 35 par 5.", ["5", "6", "7", "8"], "35 ÷ 5 = 7 autocollants chacun."],
    "TMP811_2_17": ["Dans un carré magique (somme 15), une ligne vaut : 4, 9, ?. Quel est le numéro manquant ?", "4 + 9 + ? = 15.", ["1", "2", "3", "4"], "4 + 9 + ? = 15, alors ? = 15 − 4 − 9 = 2."],
    "TMP811_2_18": ["Économisez 5 £ par semaine. En combien de semaines récoltez-vous 40 £ ?", "Divisez 40 £ par 5 £.", ["6", "7", "8", "9"], "40 £ ÷ 5 £ = 8 semaines."],
    "TMP811_2_19": ["Une imprimante imprime 10 pages par minute. Combien de temps faut-il pour imprimer 80 pages ?", "Il divise les pages en pages par minute.", ["6 minutes", "7 minutes", "8 minutes", "10 minutes"], "80 ÷ 10 = 8 minutes."],
    "TMP811_2_20": ["48 élèves sont répartis en équipes de 8. Combien d'équipes sont constituées ?", "Divisez 48 par 8.", ["4", "5", "6", "7"], "48 ÷ 8 = 6 équipes."],
    "TMP811_3_01": ["Un magasin vend des crayons à 50 pence et des stylos à 1,20 £. Vous achetez 3 crayons et 2 stylos. Combien payez-vous ?", "Calculez chaque partie séparément, puis additionnez-les ensemble.", ["3,50 £", "3,90 £", "4,10 £", "4,50 £"], "3 × 50p = 1,50 £. 2 × 1,20 £ = 2,40 £. Total : 1,50 £ + 2,40 £ = 3,90 £."],
    "TMP811_3_02": ["Une araignée a 8 pattes, un chien en a 4. Il y a 3 araignées et 2 chiens dans une pièce. Combien y a-t-il de pieds au total ?", "Calculez d'abord les pattes des araignées, puis celles des chiens.", ["28", "30", "32", "36"], "3 × 8 = 24 pattes (araignées). 2 × 4 = 8 pieds (chiens). 24 + 8 = 32."],
    "TMP811_3_03": ["L'horloge indique 15h45. Quelle heure sera-t-il dans 2 heures et 30 minutes ?", "Ajoutez d'abord les heures, puis les minutes.", ["17h15", "17h45", "18h15", "18h45"], "15h45 + 2 heures = 17h45. 17h45 + 30 minutes = 18h15."],
    "TMP811_3_04": ["Vous disposez de 3 pièces : 50p, 20p et 10p. Combien de montants différents peut-on former à l’aide d’une ou plusieurs pièces ?", "Énumérez toutes les combinaisons : un, deux, les trois.", ["5", "6", "7", "8"], "Simples : 50, 20, 10. Paires : 70, 60, 30. Tous les trois : 80. Total 7 montants."],
    "TMP811_3_05": ["Une recette demande 250 g de farine pour 4 personnes. De combien de farine avez-vous besoin pour 12 personnes ?", "12 est 3 fois plus que 4.", ["500g", "625g", "750g", "1000g"], "12 ÷ 4 = 3 fois plus. 250 × 3 = 750 g."],
    "TMP811_3_06": ["Un train part à 9h15 et arrive à 11h45. Quelle est la durée du voyage?", "Comptez les heures et les minutes.", ["2 heures", "2 heures et 15 minutes", "2 heures et 30 minutes", "3 heures"], "De 9h15 à 11h15 = 2 heures. De 11h15 à 11h45 = 30 minutes. Total : 2 heures et 30 minutes."],
    "TMP811_3_07": ["Vous achetez des produits qui coûtent 2,50 £, 3,75 £, 1,25 £ et 4,50 £. Combien d'argent gagnez-vous avec 20 £ ?", "Additionnez tous les prix, puis soustrayez de 20 £.", ["6,00 £", "7,00 £", "8,00 £", "9,00 £"], "2,50 £ + 3,75 £ + 1,25 £ + 4,50 £ = 12,00 £. Reste : 20 £ − 12 £ = 8,00 £."],
    "TMP811_3_08": ["Dans une pièce il y a des chaises (4 pieds chacune) et des tabourets (3 pieds chacun). Il y a 5 chaises et quelques tabourets. Au total, il y a 29 pieds. Combien y a-t-il de tabourets ?", "Calculez d’abord les pieds de la chaise, puis trouvez les tabourets.", ["2", "3", "4", "5"], "5 chaises × 4 = 20 pieds. 29 − 20 = 9 pieds restants. 9 ÷ 3 = 3 tabourets."],
    "TMP811_3_09": ["Il faut 5 minutes pour couper une bûche en 2 morceaux. Combien de temps faut-il pour le couper en 4 morceaux ?", "Pour 4 pièces, il faut 3 coupes et non 4.", ["10 minutes", "15 minutes", "20 minutes", "25 minutes"], "4 pièces = 3 coupes. 3 × 5 = 15 minutes."],
    "TMP811_3_10": ["Un bus transporte 45 passagers. 3 bus sont nécessaires pour un voyage scolaire. Quel est le nombre maximum d’étudiants pouvant y aller ?", "Multipliez les sièges dans le bus par le nombre de bus.", ["90", "120", "135", "150"], "3 × 45 = 135 étudiants au maximum."],
    "TMP811_3_11": ["Vous commencez avec 100 £. Vous dépensez un quart, puis un tiers de ce qui reste. Combien te reste-t-il ?", "Un quart de 100 = 25. Puis un tiers de 75.", ["40 £", "45 £", "50 £", "55 £"], "Quart de 100 £ = 25 £ dépensés, 75 £ restants. Un tiers de 75 £ = 25 £ dépensés. 75 £ - 25 £ = 50 £."],
    "TMP811_3_12": ["Une séance commence à 14h50 et dure 1 heure et 25 minutes. A quelle heure ça se termine ?", "Ajoutez 1 heure, puis 25 minutes.", ["15h55", "16h05", "16h15", "16h25"], "14h50 + 1 heure = 15h50. 15h50 + 25 minutes = 16h15."],
    "TMP811_3_13": ["Il y a deux fois plus de filles que de garçons dans une classe. Il y a 12 garçons. Combien y a-t-il d’enfants au total ?", "Filles = 2 × garçons.", ["24", "30", "36", "48"], "Filles = 2 × 12 = 24. Total = 12 + 24 = 36 enfants."],
    "TMP811_3_14": ["Vous souhaitez clôturer un jardin carré d'un côté de 8m. La clôture coûte 5 £ par mètre. Quel est le coût total ?", "Trouvez d’abord le périmètre, puis multipliez par le prix au mètre.", ["120 £", "140 £", "160 £", "200 £"], "Périmètre = 4 × 8 = 32 m. Coût = 32 × 5 £ = 160 £."],
    "TMP811_3_15": ["Un film commence à 19h40 et dure 1 heure et 50 minutes. A quelle heure ça se termine ?", "Ajoutez 1 heure (vous obtenez 20h40), puis 50 minutes.", ["21h10", "21h20", "21h30", "21h40"], "19h40 + 1 heure = 20h40. 20h40 + 50 minutes = 21h30."],
    "TMP811_3_16": ["Il y a des vaches et des poules dans une cour. Numéros 8 têtes et 26 pieds. combien y a-t-il de vaches", "La vache a 4 pattes, la poule en a 2. Vous pouvez vérifier en essayant.", ["3", "4", "5", "6"], "8 têtes. S'ils étaient tous des poulets : 8 × 2 = 16 pieds. De plus : 26 − 16 = 10. Chaque vache ajoute 2 pattes supplémentaires : 10 ÷ 2 = 5 vaches."],
    "TMP811_3_17": ["En utilisant des pièces de 5p, 10p et 20p, de combien de manières différentes pouvez-vous gagner exactement 25p ?", "Répertorie toutes les combinaisons qui totalisent 25p.", ["2", "3", "4", "5"], "Quatre modes : (1) 20+5, (2) 10+10+5, (3) 10+5+5+5, (4) 5+5+5+5+5."],
    "TMP811_3_18": ["Une piste de course mesure 400 m de long. Un athlète court 3 tours. Combien de kilomètres parcourt-il ?", "1km = 1000m.", ["0,8km", "1,0km", "1,2km", "1,5km"], "3 × 400 = 1 200 m = 1,2 km."],
    "TMP811_3_19": ["Une boîte contient 24 bonbons. Vous en avez besoin pour 100 personnes (une pour chacune). Combien de boîtes devez-vous acheter ?", "4 cases = 96 (pas assez). Essayez 5 boîtes.", ["4", "5", "6", "10"], "4 cases = 96 (pas assez). 5 boîtes = 120 (assez). Vous devez en acheter 5."],
    "TMP811_3_20": ["Deux nombres ont une somme de 50. L’un est 14 plus grand que l’autre. Quel est le plus grand nombre ?", "Marquez le plus petit nombre avec un x. Alors x + (x + 14) = 50.", ["28", "30", "32", "36"], "x + (x + 14) = 50. 2x = 36. x = 18. Plus grand = 18 + 14 = 32."],
  }
});
